    others.forEach(B => {
      const idx = B.referrerChain.indexOf(A.address);
      if (idx !== -1) {
        const pathBetween = B.referrerChain.slice(0, idx);
        const hasOtherMarkedInBetween = pathBetween.some(mid => 
          rawData.some(r => r.address === mid)
        );
        if (!hasOtherMarkedInBetween) {
          nearestChildren.push(B.address);
        }
      }
    });

    const childrenStakingSum = nearestChildren.reduce((acc, childAddr) => {
      const child = rawData.find(r => r.address === childAddr);
      return acc + (child ? child.teamStaking : 0);
    }, 0);

    return {
      address: A.address,
      date: today,
      metrics: {
        label: A.label,
        warZone: A.warZone,
        level: A.level,
        directReferrals: A.directReferrals,
        teamNumber: A.teamNumber,
        teamStaking: A.teamStaking,
        effectiveStaking: Math.max(0, A.teamStaking - childrenStakingSum),
        referrer: A.referrerChain[0] || null,
        nearestLabeledChildren: nearestChildren
      }
    };
  });

  // 4. 写入 Supabase
  console.log('💾 正在保存快照到数据库...');
  for (const item of finalMetrics) {
    const { error } = await supabase.from('snapshots').upsert({
      address: item.address,
      date: item.date,
      metrics: item.metrics
    }, { onConflict: 'address,date' });
    if (error) console.error(`保存失败 ${item.address}:`, error.message);
    await delay(200); // 写入间隔
  }

  // 5. 更新 tracked_addresses 中的等级
  console.log('🏷️ 更新地址等级信息...');
  for (const item of rawData) {
    await supabase.from('tracked_addresses').update({ level: item.level }).eq('address', item.address);
    await delay(100); // 更新间隔
  }

  console.log('✅ 同步任务圆满完成！');
}

runSync().catch(err => {
  console.error('❌ 同步过程中出现致命错误:', err);
  (process as any).exit(1);
});

import { createClient } from '@supabase/supabase-js';

// 从环境变量读取配置
const supabaseUrl = process.env.SUPABASE_URL!;
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY!;
const supabase = createClient(supabaseUrl, supabaseAnonKey);

const PRECISION = 9;
const MAX_RETRIES = 5; // 最大重试次数
const BASE_RETRY_DELAY = 10000; // 基础重试间隔 10 秒
const BATCH_SIZE = 3; // 每批次处理 3 个地址

// --- 工具函数 ---

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * 带有递增重试逻辑的 fetch 包装器
 * 报错后等待时间随重试次数增加
 */
async function fetchWithRetry(url: string, options: any, description: string): Promise<any> {
  let lastError: any;
  for (let i = 0; i < MAX_RETRIES; i++) {
    try {
      const res = await fetch(url, options);
      if (!res.ok) {
        throw new Error(`HTTP ${res.status}`);
      }
      const text = await res.text();
      if (!text) return null;
      return JSON.parse(text);
    } catch (e: any) {
      lastError = e;
      const currentDelay = (i + 1) * BASE_RETRY_DELAY;
      console.warn(`⚠️ [${description}] 尝试第 ${i + 1} 次失败: ${e.message}。等待 ${currentDelay / 1000}s 后重试...`);
      if (i < MAX_RETRIES - 1) {
        await delay(currentDelay);
      }
    }
  }
  console.error(`❌ [${description}] 在尝试 ${MAX_RETRIES} 次后全部失败。`);
  return null;
}

// --- 基础 API 函数 ---

const formatStaking = (raw: string | number): number => {
  try {
    const val = typeof raw === 'string' ? BigInt(raw) : BigInt(Math.floor(Number(raw)));
    return Number(val) / Math.pow(10, PRECISION);
  } catch (e) {
    return 0;
  }
};

const fetchLevel = async (address: string) => {
  const data = await fetchWithRetry(
    `https://apiv2.ocros.io/api/v1/community/${address}`,
    {
      method: "POST",
      headers: { "accept": "*/*", "Referer": "https://origindefi.io/" }
    },
    `fetchLevel ${address}`
  );
  return data?.level || 'Unknown';
};

const fetchInviteData = async (address: string) => {
  const data = await fetchWithRetry(
    `https://apiv2.ocros.io/api/v1/communities/getInviteData?address=${address}&level=undefined`,
    { headers: { "accept": "application/json", "Referer": "https://origindefi.io/" } },
    `fetchInviteData ${address}`
  );
  return data || { directReferralQuantity: 0, teamNumber: '0' };
};

const fetchStakingStatus = async (address: string) => {
  const data = await fetchWithRetry(
    `https://api.ocros.io/v1/api/comm/queryStakingStatus?member=${address}`,
    {
      method: "POST",
      headers: { "content-type": "application/json", "Referer": "https://origindefi.io/" }
    },
    `fetchStakingStatus ${address}`
  );
  return data || { teamStaking: '0', role: 'Unknown' };
};

const fetchReferrer = async (address: string): Promise<string | null> => {
  const addressParam = address.replace(/^0x/, '').toLowerCase().padStart(64, '0');
  const bodyData = "0x08ae4b0c" + addressParam;

  const resData = await fetchWithRetry(
    "https://greatest-powerful-feather.matic.quiknode.pro/d05012eaa00b33a3aa3e8e7981b2d658f4281815/",
    {
      method: "POST",
      headers: { "content-type": "application/json", "Referer": "https://origindefi.io/" },
      body: JSON.stringify({
        "method": "eth_call",
        "params": [{ "to": "0x6757165973042541ebdec47b73283397b5afd90e", "data": bodyData }, "latest"],
        "id": 44, "jsonrpc": "2.0"
      })
    },
    `fetchReferrer ${address}`
  );

  if (resData?.result && resData.result !== '0x') {
    const hex = resData.result.slice(2);
    if (hex.length < 128) return null;
    const referrer = '0x' + hex.slice(64, 128).slice(24);
    if (referrer === '0x' + '0'.repeat(40)) return null;
    return referrer.toLowerCase();
  }
  return null;
};

const fetchFullChain = async (address: string, cache: Map<string, string | null>) => {
  const chain: string[] = [];
  let current: string | null = address.toLowerCase();
  while (current && chain.length < 100) {
    let next = cache.has(current) ? cache.get(current)! : await fetchReferrer(current);
    cache.set(current, next);
    if (!next) break;
    chain.push(next);
    current = next;
    await delay(200); // 内部微延迟
  }
  return chain;
};

// --- 同步任务主逻辑 ---

async function runSync() {
  console.log('🚀 开始执行每日同步任务...');

  // 1. 获取所有待追踪地址
  const { data: dbAddresses, error: dbError } = await supabase.from('tracked_addresses').select('*');
  if (dbError || !dbAddresses) throw new Error('读取地址列表失败');

  console.log(`📊 共有 ${dbAddresses.length} 个地址待同步，将分批处理 (每批 ${BATCH_SIZE} 个) 以平衡效率与频率限制。`);

  const today = new Date().toISOString().split('T')[0];
  const referralCache = new Map<string, string | null>();
  const rawData: any[] = [];

  // 2. 分批抓取数据
  for (let i = 0; i < dbAddresses.length; i += BATCH_SIZE) {
    const batch = dbAddresses.slice(i, i + BATCH_SIZE);
    console.log(`📡 [批次处理] 正在同步第 ${i + 1} 到 ${Math.min(i + BATCH_SIZE, dbAddresses.length)} 个地址...`);

    const results = await Promise.all(batch.map(async (item) => {
      try {
        // 每个地址内部的数据抓取仍然保持一定的串行或极短延迟，防止瞬时并发极高
        const invite = await fetchInviteData(item.address);
        const stake = await fetchStakingStatus(item.address);
        const chain = await fetchFullChain(item.address, referralCache);
        const level = await fetchLevel(item.address);

        return {
          address: item.address.toLowerCase(),
          label: item.label,
          warZone: item.war_zone,
          level,
          directReferrals: invite.directReferralQuantity,
          teamNumber: parseInt(invite.teamNumber || '0'),
          teamStaking: formatStaking(stake.teamStaking),
          referrerChain: chain
        };
      } catch (err) {
        console.error(`❌ 处理地址 ${item.address} 时出现错误:`, err);
        return null;
      }
    }));

    // 过滤掉失败的地址并加入结果集
    rawData.push(...results.filter(r => r !== null));

    // 批次之间增加延迟
    if (i + BATCH_SIZE < dbAddresses.length) {
      console.log(`⏳ 批次完成，等待 5s 进入下一批...`);
      await delay(5000);
    }
  }

  // 3. 计算有效业绩 (核心扣除逻辑)
  console.log('🧮 正在计算业绩层级关系...');
  const finalMetrics = rawData.map(A => {
    const nearestChildren: string[] = [];
    const others = rawData.filter(X => X.address !== A.address);

    others.forEach(B => {
      const idx = B.referrerChain.indexOf(A.address);
      if (idx !== -1) {
        const pathBetween = B.referrerChain.slice(0, idx);
        const hasOtherMarkedInBetween = pathBetween.some(mid => 
          rawData.some(r => r.address === mid)
        );
        if (!hasOtherMarkedInBetween) {
          nearestChildren.push(B.address);
        }
      }
    });

    const childrenStakingSum = nearestChildren.reduce((acc, childAddr) => {
      const child = rawData.find(r => r.address === childAddr);
      return acc + (child ? child.teamStaking : 0);
    }, 0);

    return {
      address: A.address,
      date: today,
      metrics: {
        label: A.label,
        warZone: A.warZone,
        level: A.level,
        directReferrals: A.directReferrals,
        teamNumber: A.teamNumber,
        teamStaking: A.teamStaking,
        effectiveStaking: Math.max(0, A.teamStaking - childrenStakingSum),
        referrer: A.referrerChain[0] || null,
        nearestLabeledChildren: nearestChildren
      }
    };
  });

  // 4. 写入 Supabase
  console.log('💾 正在保存快照到数据库...');
  for (const item of finalMetrics) {
    const { error } = await supabase.from('snapshots').upsert({
      address: item.address,
      date: item.date,
      metrics: item.metrics
    }, { onConflict: 'address,date' });
    if (error) console.error(`保存失败 ${item.address}:`, error.message);
    await delay(100); 
  }

  // 5. 更新 tracked_addresses 中的等级
  console.log('🏷️ 更新地址等级信息...');
  for (const item of rawData) {
    await supabase.from('tracked_addresses').update({ level: item.level }).eq('address', item.address);
  }

  console.log('✅ 同步任务圆满完成！');
}

runSync().catch(err => {
  console.error('❌ 同步过程中出现致命错误:', err);
  (process as any).exit(1);
});

import { InviteData, StakingData } from '../types';

const PRECISION = 9;

/**
 * 验证以太坊风格地址合法性
 */
export const isValidAddress = (address: string): boolean => {
  return /^0x[a-fA-F0-9]{40}$/.test(address);
};

export const formatStaking = (raw: string | number): number => {
  try {
    const val = typeof raw === 'string' ? BigInt(raw) : BigInt(Math.floor(Number(raw)));
    return Number(val) / Math.pow(10, PRECISION);
  } catch (e) {
    return 0;
  }
};

// 获取地址等级 Level
export const fetchLevel = async (address: string): Promise<string> => {
  try {
    const res = await fetch(`https://apiv2.ocros.io/api/v1/community/${address}`, {
      method: "POST",
      headers: {
        "accept": "*/*",
        "Referer": "https://origindefi.io/",
      }
    });
    if (!res.ok) return 'Unknown';
    const text = await res.text();
    if (!text) return 'Unknown';
    const data = JSON.parse(text);
    return data.level || 'Unknown';
  } catch (error) {
    console.error("Fetch level error:", error);
    return 'Error';
  }
};

export const fetchInviteData = async (address: string): Promise<InviteData> => {
  try {
    const url = `https://apiv2.ocros.io/api/v1/communities/getInviteData?address=${address}&level=undefined`;
    const res = await fetch(url, {
      headers: {
        "accept": "application/json",
        "Referer": "https://origindefi.io/",
      }
    });
    if (!res.ok) return { directReferralQuantity: 0, teamNumber: '0' };
    const text = await res.text();
    if (!text) return { directReferralQuantity: 0, teamNumber: '0' };
    return JSON.parse(text);
  } catch (e) {
    return { directReferralQuantity: 0, teamNumber: '0' };
  }
};

export const fetchStakingStatus = async (address: string): Promise<StakingData> => {
  try {
    const res = await fetch(`https://api.ocros.io/v1/api/comm/queryStakingStatus?member=${address}`, {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "Referer": "https://origindefi.io/",
      }
    });
    if (!res.ok) return { teamStaking: '0', role: 'Unknown' };
    const text = await res.text();
    if (!text) return { teamStaking: '0', role: 'Unknown' };
    return JSON.parse(text);
  } catch (e) {
    return { teamStaking: '0', role: 'Unknown' };
  }
};

export const fetchReferrer = async (address: string): Promise<string | null> => {
  const addressParam = address.replace(/^0x/, '').toLowerCase().padStart(64, '0');
  const data = "0x08ae4b0c" + addressParam;

  try {
    const res = await fetch("https://greatest-powerful-feather.matic.quiknode.pro/d05012eaa00b33a3aa3e8e7981b2d658f4281815/", {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "Referer": "https://origindefi.io/",
      },
      body: JSON.stringify({
        "method": "eth_call",
        "params": [
          {
            "to": "0x6757165973042541ebdec47b73283397b5afd90e",
            "data": data
          },
          "latest"
        ],
        "id": 44,
        "jsonrpc": "2.0"
      })
    });

    const resData = await res.json();
    const result = resData.result;
    if (result && result !== '0x') {
      const hex = result.startsWith("0x") ? result.slice(2) : result;
      if (hex.length < 128) return null;
      const referrerHex = hex.slice(64, 128);
      const referrer = '0x' + referrerHex.slice(24);
      const zeroAddr = '0x' + '0'.repeat(40);
      if (referrer.toLowerCase() === zeroAddr) return null;
      return '0x' + referrer.slice(2).toLowerCase();
    }
  } catch (error) {
    console.error("Referrer fetch error:", error);
  }
  return null;
};

export const fetchFullChain = async (
  address: string, 
  cache: Map<string, string | null> = new Map()
): Promise<string[]> => {
  const chain: string[] = [];
  let current: string | null = address.toLowerCase();
  const maxDepth = 100;

  while (current && chain.length < maxDepth) {
    let next: string | null;
    if (cache.has(current)) {
      next = cache.get(current)!;
    } else {
      next = await fetchReferrer(current);
      cache.set(current, next);
    }
    if (!next) break;
    chain.push(next);
    current = next;
  }
  return chain;
};

/**
 * 向上追溯，直到遇到已标记地址或到达0地址
 */
export const fetchChainUntilLabeled = async (
  address: string,
  isLabeled: (addr: string) => boolean,
  cache: Map<string, string | null> = new Map()
): Promise<string[]> => {
  const chain: string[] = [];
  let current: string | null = address.toLowerCase();
  const maxDepth = 100;

  while (current && chain.length < maxDepth) {
    let next: string | null;
    if (cache.has(current)) {
      next = cache.get(current)!;
    } else {
      next = await fetchReferrer(current);
      cache.set(current, next);
    }

    if (!next) break;
    chain.push(next);

    // 如果这个推荐人已经是被标记的，停止进一步查询
    if (isLabeled(next)) break;

    current = next;
  }
  return chain;
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrackedAddress, 
  AddressMetrics, 
  Snapshot 
} from './types';
import * as db from './services/dbService';
import * as api from './services/apiService';
import { isSupabaseConfigured } from './services/supabaseClient';
import AddressTable from './components/AddressTable';

const ITEMS_PER_PAGE = 100;
const SYNC_BATCH_SIZE = 5;

const App: React.FC = () => {
  const [addresses, setAddresses] = useState<TrackedAddress[]>([]);
  const [snapshots, setSnapshots] = useState<Snapshot[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isPathLoading, setIsPathLoading] = useState(false);
  const [loadingAddress, setLoadingAddress] = useState<string | null>(null);
  const [initError, setInitError] = useState<string | null>(null);

  const [newAddr, setNewAddr] = useState('');
  const [newLabel, setNewLabel] = useState('');
  const [newWarZone, setNewWarZone] = useState('1');
  const [searchTerm, setSearchTerm] = useState('');

  const [filterWarZone, setFilterWarZone] = useState<string>('all');
  const [filterLevel, setFilterLevel] = useState<string>('all');
  const [currentPage, setCurrentPage] = useState(1);

  const [showHistoryModal, setShowHistoryModal] = useState<AddressMetrics | null>(null);
  const [showPathModal, setShowPathModal] = useState<{
    address: string, 
    chain: string[], 
    isDeepSearch?: boolean,
    chainMetrics?: Record<string, AddressMetrics | null>
  } | null>(null);
  const [lastSyncDate, setLastSyncDate] = useState<string | null>(null);

  const loadData = async () => {
    if (!isSupabaseConfigured) {
      setInitError("【环境变量缺失】未检测到 Supabase 配置。");
      return;
    }

    setIsLoading(true);
    try {
      const [addrs, history] = await Promise.all([
        db.getTrackedAddresses(),
        db.getSnapshots()
      ]);
      setAddresses(addrs);
      setSnapshots(history);
      if (history.length > 0) {
        setLastSyncDate(history[0].date);
      }
      setInitError(null);
    } catch (err: any) {
      console.error(err);
      setInitError(`连接异常: ${err.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const runSync = async () => {
    if (addresses.length === 0) {
      alert("请先添加需要追踪的地址");
      return;
    }

    setIsLoading(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const referralCache = new Map<string, string | null>();
      const rawData: any[] = [];

      // 分批执行同步，每批5个
      for (let i = 0; i < addresses.length; i += SYNC_BATCH_SIZE) {
        const batch = addresses.slice(i, i + SYNC_BATCH_SIZE);
        const batchResults = await Promise.all(batch.map(async (item) => {
          try {
            const [invite, stake, chain, level] = await Promise.all([
              api.fetchInviteData(item.address),
              api.fetchStakingStatus(item.address),
              api.fetchFullChain(item.address, referralCache),
              api.fetchLevel(item.address)
            ]);

            // 基础检查：如果 stake 返回了 0 且没有任何数据，可能是请求失败，不应覆盖（此处保持原有逻辑，通过try-catch保护）
            return {
              ...item,
              level, 
              directReferrals: invite.directReferralQuantity,
              teamNumber: parseInt(invite.teamNumber || '0'),
              teamStaking: api.formatStaking(stake.teamStaking),
              referrerChain: chain, 
              referrer: chain[0] || null
            };
          } catch (e) {
            console.warn(`同步地址 ${item.address} 失败，将跳过快照。`, e);
            return null;
          }
        }));
        rawData.push(...batchResults.filter(r => r !== null));
      }

      // 如果没有任何成功的数据，不进行后续操作
      if (rawData.length === 0) {
        throw new Error("同步失败：未能获取任何有效数据");
      }

      // 批量保存更新后的等级
      await Promise.all(rawData.map(r => db.saveTrackedAddress({
        address: r.address,
        label: r.label,
        warZone: r.warZone,
        level: r.level
      })));

      // 计算有效业绩
      const metrics: AddressMetrics[] = rawData.map(A => {
        const nearestChildren: string[] = [];
        const otherLabeledAddresses = rawData.filter(X => X.address.toLowerCase() !== A.address.toLowerCase());

        otherLabeledAddresses.forEach(B => {
          const aAddr = A.address.toLowerCase();
          if (B.referrerChain.some(anc => anc.toLowerCase() === aAddr)) {
            const idx = B.referrerChain.findIndex(anc => anc.toLowerCase() === aAddr);
            const pathBetween = B.referrerChain.slice(0, idx);
            const isNearest = !pathBetween.some(mid => 
              otherLabeledAddresses.some(label => label.address.toLowerCase() === mid.toLowerCase())
            );
            if (isNearest) {
              nearestChildren.push(B.address);
            }
          }
        });

        const childrenStakingSum = nearestChildren.reduce((acc, childAddr) => {
          const childData = rawData.find(r => r.address.toLowerCase() === childAddr.toLowerCase());
          return acc + (childData ? childData.teamStaking : 0);
        }, 0);

        return {
          address: A.address,
          label: A.label,
          warZone: A.warZone,
          level: A.level,
          directReferrals: A.directReferrals,
          teamNumber: A.teamNumber,
          teamStaking: A.teamStaking,
          effectiveStaking: Math.max(0, A.teamStaking - childrenStakingSum),
          referrer: A.referrer,
          nearestLabeledChildren: nearestChildren
        };
      });

      // 保存快照
      await Promise.all(metrics.map(m => {
        const { address, label, warZone, level, ...rest } = m;
        return db.saveSnapshotRecord(m.address, today, {
          ...rest,
          label,
          warZone,
          level
        });
      }));

      await db.cleanupOldSnapshots();
      await loadData();
      alert("同步完成");
    } catch (err: any) {
      console.error(err);
      alert(err.message || "同步失败，请检查网络。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddAddress = async () => {
    if (!newAddr || !newLabel) return;
    const addrFormatted = newAddr.trim().toLowerCase();

    // 地址合法性校验
    if (!api.isValidAddress(addrFormatted)) {
      alert("请输入合法的钱包地址 (0x 开头的 40 位 16 进制字符)");
      return;
    }

    if (addresses.some(a => a.address.toLowerCase() === addrFormatted)) {
      alert("地址已存在于标记列表中");
      return;
    }

    setIsLoading(true);
    try {
      // 1. 获取基础信息（等级）
      const level = await api.fetchLevel(addrFormatted);
      const item: TrackedAddress = { 
        address: addrFormatted, 
        label: newLabel.trim(), 
        warZone: newWarZone,
        level: level 
      };

      // 2. 保存地址标记
      await db.saveTrackedAddress(item);

      // 3. 立即为该地址同步今日数据
      const today = new Date().toISOString().split('T')[0];
      const [invite, stake, chain] = await Promise.all([
        api.fetchInviteData(addrFormatted),
        api.fetchStakingStatus(addrFormatted),
        api.fetchFullChain(addrFormatted)
      ]);

      const teamStaking = api.formatStaking(stake.teamStaking);

      // 这里的有效业绩由于新加地址可能改变已有树结构，建议在添加后全量重新计算或至少保存单点原始快照
      // 为简化，保存单点数据，并在完成后刷新列表
      await db.saveSnapshotRecord(addrFormatted, today, {
        label: item.label,
        warZone: item.warZone,
        level: item.level,
        directReferrals: invite.directReferralQuantity,
        teamNumber: parseInt(invite.teamNumber || '0'),
        teamStaking: teamStaking,
        effectiveStaking: teamStaking, // 初始有效设为总质押，下一次全局同步会修正
        referrer: chain[0] || null,
        nearestLabeledChildren: []
      });

      await loadData();
      setNewAddr('');
      setNewLabel('');
      alert(`已成功添加标记并同步数据: ${item.label}`);
    } catch (err) {
      console.error(err);
      alert("添加失败，请检查网络连接");
    } finally {
      setIsLoading(false);
    }
  };

  const getTodayMetric = (addr: string): AddressMetrics | null => {
    const todayStr = new Date().toISOString().split('T')[0];
    const latest = snapshots.find(s => s.date === todayStr) || snapshots[0];
    if (!latest) return null;
    return latest.data.find(d => d.address.toLowerCase() === addr.toLowerCase()) || null;
  };

  const getAddressLabel = (addr: string) => {
    const found = addresses.find(a => a.address.toLowerCase() === addr.toLowerCase());
    return found ? found.label : null;
  };

  const warZoneOptions = useMemo(() => {
    const zones = Array.from(new Set(addresses.map(a => a.warZone).filter(Boolean)));
    return zones.sort();
  }, [addresses]);

  const levelOptions = useMemo(() => {
    const levels = Array.from(new Set(addresses.map(a => a.level).filter(Boolean)));
    return levels.sort();
  }, [addresses]);

  const { filteredFull, paginatedData, totalCount } = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const latest = snapshots.find(s => s.date === todayStr) || snapshots[0];
    if (!latest) return { filteredFull: [], paginatedData: [], totalCount: 0 };

    const full = latest.data.filter(item => {
      const search = searchTerm.toLowerCase();
      const matchesSearch = item.label.toLowerCase().includes(search) || 
                            item.address.toLowerCase().includes(search) || 
                            item.warZone?.toLowerCase().includes(search) ||
                            item.level?.toLowerCase().includes(search);

      const matchesWarZone = filterWarZone === 'all' || item.warZone === filterWarZone;
      const matchesLevel = filterLevel === 'all' || item.level === filterLevel;

      return matchesSearch && matchesWarZone && matchesLevel;
    });

    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    const paginated = full.slice(start, start + ITEMS_PER_PAGE);

    return { 
      filteredFull: full, 
      paginatedData: paginated, 
      totalCount: full.length 
    };
  }, [snapshots, searchTerm, filterWarZone, filterLevel, currentPage]);

  const fetchPath = async (address: string) => {
    if (isPathLoading) return;
    setIsPathLoading(true);
    setLoadingAddress(address);
    try {
      const chain = await api.fetchFullChain(address);
      const metrics: Record<string, AddressMetrics | null> = {};
      chain.forEach(addr => {
        metrics[addr] = getTodayMetric(addr);
      });
      setShowPathModal({ address, chain, chainMetrics: metrics });
    } catch (err) {
      alert("路径查询失败");
    } finally {
      setIsPathLoading(false);
      setLoadingAddress(null);
    }
  };

  const handleTraceInputPath = async () => {
    const searchAddr = searchTerm.trim().toLowerCase();
    if (!api.isValidAddress(searchAddr)) {
      alert("请输入正确的钱包地址进行路径追溯");
      return;
    }
    setIsPathLoading(true);
    setLoadingAddress('search_input');
    try {
      const chain = await api.fetchChainUntilLabeled(
        searchAddr, 
        (addr) => !!getAddressLabel(addr)
      );
      const metrics: Record<string, AddressMetrics | null> = {};
      chain.forEach(addr => {
        metrics[addr] = getTodayMetric(addr);
      });
      setShowPathModal({ address: searchAddr, chain, isDeepSearch: true, chainMetrics: metrics });
    } catch (err) {
      alert("追溯失败");
    } finally {
      setIsPathLoading(false);
      setLoadingAddress(null);
    }
  };

  const isTodaySynced = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return snapshots.some(s => s.date === todayStr);
  }, [snapshots]);

  return (
    <div className="min-h-screen pb-12 bg-slate-50 text-slate-900 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-sm shadow-md">TR</div>
            <h1 className="text-lg font-bold text-slate-900 tracking-tight">团队业绩快照</h1>
          </div>
          <div className="flex items-center space-x-4">
            <div className="hidden md:flex flex-col items-end mr-2">
              <span className="text-[10px] text-slate-400 font-bold uppercase">已标记地址</span>
              <span className="text-sm font-bold text-indigo-600">{addresses.length}</span>
            </div>
            {isSupabaseConfigured && (
              <span className={`text-[10px] uppercase tracking-widest font-bold px-2.5 py-1 rounded-full ${isTodaySynced ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-orange-50 text-orange-600 border border-orange-100'}`}>
                {isTodaySynced ? '今日已同步' : '待同步'}
              </span>
            )}
            <button
              onClick={runSync}
              disabled={isLoading || !isSupabaseConfigured}
              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all shadow-sm ${
                isLoading || !isSupabaseConfigured
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
